PRAGMA defer_foreign_keys=TRUE;
CREATE TABLE users (
  id TEXT PRIMARY KEY, -- UID from Supabase Auth
  name TEXT NOT NULL,
  email TEXT UNIQUE NOT NULL,
  roles TEXT NOT NULL, -- JSON array of UserRole
  designation TEXT,
  picture TEXT,
  department_id TEXT,
  contact_number TEXT,
  status TEXT DEFAULT 'Pending', -- Active, Inactive, Suspended, Pending
  is_verified INTEGER DEFAULT 0, -- Boolean
  must_change_pin INTEGER DEFAULT 0, -- Boolean
  certification_issued TEXT, -- ISO Date
  certification_expiry TEXT, -- ISO Date
  last_active TEXT, -- ISO Date
  created_at TEXT DEFAULT CURRENT_TIMESTAMP
, dashboard_config TEXT, renewal_requested TEXT DEFAULT NULL, password_hash TEXT);
CREATE TABLE departments (
  id TEXT PRIMARY KEY,
  name TEXT NOT NULL,
  abbr TEXT NOT NULL,
  head_of_dept_id TEXT,
  description TEXT,
  audit_group_id TEXT,
  is_exempted INTEGER DEFAULT 0,
  created_at TEXT DEFAULT CURRENT_TIMESTAMP
, total_assets INTEGER DEFAULT 0, uninspected_asset_count INTEGER DEFAULT 0, tier TEXT, is_task_force INTEGER DEFAULT 0, auditors_required INTEGER DEFAULT 2, is_archived INTEGER DEFAULT 0, archived_by TEXT, archived_at TEXT);
CREATE TABLE buildings (
  id TEXT PRIMARY KEY,
  name TEXT NOT NULL,
  abbr TEXT NOT NULL,
  description TEXT,
  created_at TEXT DEFAULT CURRENT_TIMESTAMP
, type TEXT);
CREATE TABLE locations (
  id TEXT PRIMARY KEY,
  name TEXT NOT NULL,
  abbr TEXT NOT NULL,
  department_id TEXT NOT NULL,
  building_id TEXT,
  level TEXT,
  description TEXT,
  supervisor_id TEXT,
  contact TEXT,
  is_active INTEGER DEFAULT 1,
  status TEXT DEFAULT 'Active', -- Active, Archived, Pending_Delete
  created_at TEXT DEFAULT CURRENT_TIMESTAMP, total_assets INTEGER DEFAULT 0, uninspected_asset_count INTEGER DEFAULT 0, archived_by TEXT, archived_at TEXT,
  FOREIGN KEY (department_id) REFERENCES departments(id),
  FOREIGN KEY (building_id) REFERENCES buildings(id)
);
CREATE TABLE audit_phases (
  id TEXT PRIMARY KEY,
  name TEXT NOT NULL,
  start_date TEXT NOT NULL,
  end_date TEXT NOT NULL,
  created_at TEXT DEFAULT CURRENT_TIMESTAMP
, description TEXT, status TEXT DEFAULT 'Active');
CREATE TABLE audit_schedules (
  id TEXT PRIMARY KEY,
  department_id TEXT NOT NULL,
  location_id TEXT NOT NULL,
  supervisor_id TEXT,
  auditor1_id TEXT,
  auditor2_id TEXT,
  date TEXT,
  status TEXT DEFAULT 'Pending', -- Pending, In Progress, Completed
  phase_id TEXT NOT NULL,
  created_at TEXT DEFAULT CURRENT_TIMESTAMP, report_path TEXT, is_locked INTEGER DEFAULT NULL,
  FOREIGN KEY (department_id) REFERENCES departments(id),
  FOREIGN KEY (location_id) REFERENCES locations(id),
  FOREIGN KEY (phase_id) REFERENCES audit_phases(id)
);
CREATE TABLE system_activities (
  id TEXT PRIMARY KEY,
  type TEXT NOT NULL,
  user_id TEXT,
  message TEXT NOT NULL,
  timestamp TEXT DEFAULT CURRENT_TIMESTAMP,
  metadata TEXT, -- JSON string
  FOREIGN KEY (user_id) REFERENCES users(id)
);
CREATE TABLE system_settings (
  id TEXT PRIMARY KEY,
  value TEXT NOT NULL, -- JSON string
  updated_at TEXT DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE audit_groups (
  id TEXT PRIMARY KEY,
  name TEXT NOT NULL,
  description TEXT,
  color TEXT,
  created_at TEXT DEFAULT CURRENT_TIMESTAMP
, tier TEXT);
CREATE TABLE kpi_tiers (
  id TEXT PRIMARY KEY,
  name TEXT NOT NULL,
  min_assets INTEGER NOT NULL,
  created_at TEXT DEFAULT CURRENT_TIMESTAMP
, description TEXT);
CREATE TABLE kpi_tier_targets (
  id TEXT PRIMARY KEY,
  tier_id TEXT NOT NULL,
  phase_id TEXT NOT NULL,
  target_percentage REAL NOT NULL,
  created_at TEXT DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (tier_id) REFERENCES kpi_tiers(id),
  FOREIGN KEY (phase_id) REFERENCES audit_phases(id)
);
CREATE TABLE department_mappings (
  id TEXT PRIMARY KEY,
  source_name TEXT UNIQUE NOT NULL,
  target_department_id TEXT NOT NULL,
  created_at TEXT DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE institution_kpi_targets (
  phase_id TEXT PRIMARY KEY,
  target_percentage REAL NOT NULL
);
CREATE TABLE cross_audit_permissions (
  id TEXT PRIMARY KEY,
  auditor_dept_id TEXT,
  target_dept_id TEXT,
  auditor_group_id TEXT,
  target_group_id TEXT,
  is_active INTEGER DEFAULT 1,
  is_mutual INTEGER DEFAULT 0,
  created_at TEXT DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (auditor_dept_id) REFERENCES departments(id),
  FOREIGN KEY (target_dept_id) REFERENCES departments(id),
  FOREIGN KEY (auditor_group_id) REFERENCES audit_groups(id),
  FOREIGN KEY (target_group_id) REFERENCES audit_groups(id)
);
CREATE TABLE strategic_memos (
  id TEXT PRIMARY KEY,
  year INTEGER NOT NULL,
  institution_name TEXT NOT NULL,
  projected_kpi REAL NOT NULL,
  feasibility_score INTEGER NOT NULL,
  total_assets INTEGER NOT NULL,
  total_auditors INTEGER NOT NULL,
  risk_level TEXT NOT NULL,
  content_json TEXT NOT NULL, -- Full snapshot of entities and pairings
  r2_html_key TEXT,
  approved_by TEXT NOT NULL,
  created_at TEXT DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (approved_by) REFERENCES users(id)
);
CREATE TABLE location_mappings (id TEXT PRIMARY KEY, source_name TEXT UNIQUE NOT NULL, target_location_id TEXT NOT NULL, created_at TEXT DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (target_location_id) REFERENCES locations(id));
CREATE TABLE accounts (
  id TEXT PRIMARY KEY,
  user_id TEXT NOT NULL,
  provider TEXT NOT NULL,                   -- e.g. 'google'
  provider_account_id TEXT NOT NULL,        -- Google's stable `sub` claim
  provider_email TEXT NOT NULL,
  created_at TEXT DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE
);
CREATE TABLE sessions (
  id TEXT PRIMARY KEY,                      -- matches KV sess:{userId}.sessionId
  user_id TEXT NOT NULL,
  expires_at TEXT NOT NULL,                 -- ISO 8601
  created_at TEXT DEFAULT CURRENT_TIMESTAMP,
  ip_address TEXT,
  user_agent TEXT,
  FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE
);
CREATE INDEX idx_users_email ON users(email);
CREATE INDEX idx_locations_dept ON locations(department_id);
CREATE INDEX idx_schedules_phase ON audit_schedules(phase_id);
CREATE INDEX idx_activities_timestamp ON system_activities(timestamp);
CREATE UNIQUE INDEX idx_kpi_tier_targets_unique ON kpi_tier_targets(tier_id, phase_id);
CREATE INDEX idx_users_status ON users(status);
CREATE INDEX idx_locations_building ON locations(building_id);
CREATE INDEX idx_locations_status ON locations(status);
CREATE INDEX idx_schedules_dept ON audit_schedules(department_id);
CREATE INDEX idx_schedules_status ON audit_schedules(status);
CREATE INDEX idx_activities_user ON system_activities(user_id);
CREATE INDEX idx_deptmapping_source ON department_mappings(source_name);
CREATE UNIQUE INDEX idx_departments_unique_name ON departments(name, abbr);
CREATE UNIQUE INDEX idx_locations_unique_name ON locations(name, department_id, level, building_id);
CREATE INDEX idx_memos_year ON strategic_memos(year);
CREATE UNIQUE INDEX idx_accounts_provider
  ON accounts(provider, provider_account_id);
CREATE INDEX idx_sessions_user_id ON sessions(user_id);
